/**
 * Prisma Schema Merge Script
 *
 * Merges multiple Prisma schema files from prisma/schema/*.prisma into a single
 * schema.prisma file. This supports the module system's multi-file schema approach
 * where each module can define its own entities.
 *
 * Order of merging:
 * 1. base.prisma (datasource, generator, enums) - MUST be first
 * 2. core.prisma (Organization, User, etc.)
 * 3. subscription.prisma (Plan, Subscription, Invoice)
 * 4. All other .prisma files in alphabetical order
 *
 * Usage: npm run schema:merge
 */

import { readdir, readFile, writeFile } from 'node:fs/promises';
import { join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

// Get the directory of this script
const __filename = fileURLToPath(import.meta.url);
const __dirname = resolve(__filename, '..');

// Project root is one level up from scripts/
const PROJECT_ROOT = resolve(__dirname, '..');

// Schema paths
const SCHEMA_DIR = join(PROJECT_ROOT, 'prisma', 'schema');
const OUTPUT_FILE = join(PROJECT_ROOT, 'prisma', 'schema.prisma');

// Priority order for schema files (files not listed will be added alphabetically after)
const PRIORITY_ORDER = ['base.prisma', 'core.prisma', 'subscription.prisma'];

/**
 * Generates a header comment for the merged schema
 */
function generateHeader(): string {
  const timestamp = new Date().toISOString();
  return `// =============================================================================
// E-Menum - Merged Prisma Schema
// =============================================================================
// THIS FILE IS AUTO-GENERATED - DO NOT EDIT DIRECTLY!
//
// This schema is automatically generated by merging all .prisma files from
// the prisma/schema/ directory. To modify the schema, edit the source files
// in that directory and run: npm run schema:merge
//
// Generated: ${timestamp}
// =============================================================================

`;
}

/**
 * Generates a section separator for each merged file
 */
function generateSeparator(filename: string): string {
  const basename = filename.replace('.prisma', '');
  const title = basename.charAt(0).toUpperCase() + basename.slice(1);
  return `
// =============================================================================
// ${title.toUpperCase()} SCHEMA (from ${filename})
// =============================================================================

`;
}

/**
 * Reads and validates a Prisma schema file
 */
async function readSchemaFile(filepath: string): Promise<string> {
  const content = await readFile(filepath, 'utf-8');
  return content.trim();
}

/**
 * Sorts schema files according to priority order
 */
function sortSchemaFiles(files: string[]): string[] {
  const priorityFiles: string[] = [];
  const otherFiles: string[] = [];

  // Separate priority and non-priority files
  for (const file of files) {
    if (file.startsWith('.') || file.startsWith('_')) {
      // Skip hidden files and files starting with underscore
      continue;
    }

    if (PRIORITY_ORDER.includes(file)) {
      priorityFiles.push(file);
    } else {
      otherFiles.push(file);
    }
  }

  // Sort priority files by their defined order
  priorityFiles.sort((a, b) => {
    return PRIORITY_ORDER.indexOf(a) - PRIORITY_ORDER.indexOf(b);
  });

  // Sort other files alphabetically
  otherFiles.sort((a, b) => a.localeCompare(b));

  return [...priorityFiles, ...otherFiles];
}

/**
 * Main merge function
 */
async function mergeSchemas(): Promise<void> {
  // eslint-disable-next-line no-console
  console.log('Merging Prisma schemas...');
  // eslint-disable-next-line no-console
  console.log(`  Source: ${SCHEMA_DIR}`);
  // eslint-disable-next-line no-console
  console.log(`  Output: ${OUTPUT_FILE}`);
  // eslint-disable-next-line no-console
  console.log('');

  try {
    // Read all files in schema directory
    const allFiles = await readdir(SCHEMA_DIR);

    // Filter to only .prisma files
    const schemaFiles = allFiles.filter(
      (f) => f.endsWith('.prisma') && !f.startsWith('.') && !f.startsWith('_')
    );

    if (schemaFiles.length === 0) {
      throw new Error(`No .prisma files found in ${SCHEMA_DIR}`);
    }

    // Sort files according to priority
    const sortedFiles = sortSchemaFiles(schemaFiles);

    // eslint-disable-next-line no-console
    console.log(`Found ${sortedFiles.length} schema files:`);
    for (const file of sortedFiles) {
      // eslint-disable-next-line no-console
      console.log(`  - ${file}`);
    }
    // eslint-disable-next-line no-console
    console.log('');

    // Start with header
    let mergedContent = generateHeader();

    // Merge each file
    for (const file of sortedFiles) {
      const filepath = join(SCHEMA_DIR, file);
      const content = await readSchemaFile(filepath);

      // Add separator only if not the first file (base.prisma doesn't need it as it has its own header)
      if (file !== 'base.prisma') {
        mergedContent += generateSeparator(file);
      }

      mergedContent += content;
      mergedContent += '\n';
    }

    // Write merged schema
    await writeFile(OUTPUT_FILE, mergedContent, 'utf-8');

    // eslint-disable-next-line no-console
    console.log('Schema merge completed successfully!');
    // eslint-disable-next-line no-console
    console.log(`Output written to: ${OUTPUT_FILE}`);
  } catch (error) {
    // eslint-disable-next-line no-console
    console.error('Error merging schemas:', error);
    process.exit(1);
  }
}

// Run the script
mergeSchemas();
